# Entity module with classes implementing interfaces and inheritance
from utils import ISearchable, Status

@abstract
class BaseEntity:
    id: int
    name: str
    status: Status

    def __init__(self, id: int, name: str):
        self.id = id
        self.name = name
        self.status = Status.PENDING

    @virtual
    def get_display_name(self) -> str:
        return f"[{self.id}] {self.name}"

    @abstract
    def get_details(self) -> str: ...

class Product(BaseEntity, ISearchable):
    price: float
    category: str

    def __init__(self, id: int, name: str, price: float, category: str):
        super().__init__(id, name)
        self.price = price
        self.category = category
        self.status = Status.ACTIVE

    @override
    def get_details(self) -> str:
        return f"Product: {self.name} (${self.price}) in {self.category}"

    def matches(self, query: str) -> bool:
        return query in self.name or query in self.category

    def get_id(self) -> int:
        return self.id

class Service(BaseEntity, ISearchable):
    duration_hours: int

    def __init__(self, id: int, name: str, duration: int):
        super().__init__(id, name)
        self.duration_hours = duration
        self.status = Status.ACTIVE

    @override
    def get_details(self) -> str:
        return f"Service: {self.name} ({self.duration_hours}h)"

    @override
    def get_display_name(self) -> str:
        return f"Service #{self.id}: {self.name}"

    def matches(self, query: str) -> bool:
        return query in self.name

