# Services module with business logic using generics and higher-order functions
from utils import filter_by_predicate, Status
from entities import BaseEntity, Product, Service

class EntityService:
    entities: list[BaseEntity]

    def __init__(self):
        self.entities = []

    def add(self, entity: BaseEntity) -> None:
        self.entities.append(entity)

    def find_by_status(self, status: Status) -> list[BaseEntity]:
        return filter_by_predicate[BaseEntity](self.entities, lambda e: e.status == status)

    def find_by_id(self, target_id: int) -> BaseEntity?:
        for e in self.entities:
            if e.id == target_id:
                return Some(e)
        return None()

class SearchService:
    def search(self, items: list[ISearchable], query: str) -> list[ISearchable]:
        return filter_by_predicate[ISearchable](items, lambda item: item.matches(query))

    def format_results(self, results: list[ISearchable]) -> list[str]:
        formatted: list[str] = []
        for item in results:
            formatted.append(f"Found: {item.get_id()}")
        return formatted
